1	type Cell = [number, number];
2	
3	const countNeighbors = (cell: Cell, cells: Cell[]): number =>
4	  cells.filter((candidate) =>
5	    Math.max(
6	      Math.abs(candidate[0] - cell[0]),
7	      Math.abs(candidate[1] - cell[1])
8	    ) === 1
9	  ).length;
10	
11	const getSurroundingCells = (cell: Cell): Cell[] =>
12	  [-1, 0, 1].flatMap((dx) =>
13	    [-1, 0, 1]
14	      .filter((dy) => dx !== 0 || dy !== 0)
15	      .map((dy): Cell => [cell[0] + dx, cell[1] + dy])
16	  );
17	
18	const cellKey = (cell: Cell): string => `${cell[0]},${cell[1]}`;
19	
20	export function nextGeneration(cells: Cell[]): Cell[] {
21	  const liveKeys = new Set(cells.map(cellKey));
22	
23	  const survivors = cells.filter((cell) => {
24	    const neighborCount = countNeighbors(cell, cells);
25	    return neighborCount === 2 || neighborCount === 3;
26	  });
27	
28	  const deadCandidateKeys = new Set<string>();
29	  const deadCandidates: Cell[] = [];
30	  for (const cell of cells) {
31	    for (const neighbor of getSurroundingCells(cell)) {
32	      const key = cellKey(neighbor);
33	      if (!liveKeys.has(key) && !deadCandidateKeys.has(key)) {
34	        deadCandidateKeys.add(key);
35	        deadCandidates.push(neighbor);
36	      }
37	    }
38	  }
39	
40	  const born = deadCandidates.filter((cell) => countNeighbors(cell, cells) === 3);
41	
42	  return [...survivors, ...born];
43	}
44

